declare @message nvarchar(4000), @udfQuantityPrice char(1), @taxProperty varchar(3), @taxCode varchar(32), @taxRate numeric(5,2), @taxAccount varchar(32), @taxType tinyint
declare @reportFormName nvarchar(512), @taxPropertyName nvarchar(512), @taxCodeName nvarchar(512), @taxAccountName nvarchar(512)
