select @taxCode = rtrim(val) from options where name = 'm_ma_thue_1'

if exists(select 1 from dmthue where ma_thue = @taxCode) begin
  select @reportFormName = case when @@language = 'v' then ten_bc else ten_bc2 end from dmmaubc3 where mau_bc = '&DefaultReportForm;'
  select @taxPropertyName = case when @@language = 'v' then rtrim(ten_tc) else rtrim(ten_tc2) end from v20dmtcthue where ma_tc = @taxProperty
  select @taxRate = a.thue_suat, @taxCodeName = case when @@language = 'v' then rtrim(a.ten_thue) else rtrim(a.ten_thue2) end,
    @taxAccount = rtrim(a.tk_thue_co3), @taxAccountName = case when @@language = 'v' then rtrim(b.ten_tk) else rtrim(b.ten_tk2) end,
    @taxType = b.tk_cn from dmthue a left join dmtk b on a.tk_thue_co3 = b.tk where a.ma_thue = @taxCode

  if @taxType is null select @taxAccount = '', @taxAccountName = '', @taxType = 0
  select @taxPropertyName = isnull(@taxPropertyName, '')

  select @message = @message + replace('$TaxRate = ' + rtrim(str(@taxRate, 5, 2)) + ';$TaxProperty = ''' + @taxProperty + ''';$TaxCode = ''' + @taxCode + ''';$TaxAccount = ''' + @taxAccount + ''';$TaxType = ' + rtrim(@taxType) + ';this._reportFormName = ''' + @reportFormName + ''';this._taxPropertyName = ''' + @taxPropertyName + ''';this._taxAccountName = ''' + @taxAccountName + ''';this._taxCodeName = ''' + @taxCodeName + ''';', '$', 'this._default')
end

